BEGIN;  CREATE TABLE IF NOT EXISTS public.delivery_plan_actual_repair_audit (   id uuid PRIMARY KEY DEFAULT gen_random_uuid(),   plan_id uuid NOT NULL REFERENCES public.delivery_plans(id),   old_actual_qty numeric NOT NULL,   new_actual_qty numeric NOT NULL,   reason text NOT NULL,   repaired_at timestamptz NOT NULL DEFAULT now(),   repaired_by text NOT NULL DEFAULT current_user );  ALTER TABLE public.delivery_plan_actual_repair_audit ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "delivery_plan_actual_repair_audit_select" ON public.delivery_plan_actual_repair_audit; CREATE POLICY "delivery_plan_actual_repair_audit_select" ON public.delivery_plan_actual_repair_audit FOR SELECT TO authenticated USING (public.is_manager()); REVOKE ALL ON TABLE public.delivery_plan_actual_repair_audit FROM PUBLIC, anon, authenticated; GRANT SELECT ON TABLE public.delivery_plan_actual_repair_audit TO authenticated;  CREATE TEMP TABLE repair_expected (   plan_id uuid PRIMARY KEY,   expected_old_actual numeric NOT NULL,   expected_new_actual numeric NOT NULL ) ON COMMIT DROP;  INSERT INTO pg_temp.repair_expected(plan_id, expected_old_actual, expected_new_actual) VALUES ('33aaa072-b90a-4f02-9310-7a9457a75244',1199,1200), ('a02f037e-390a-4e17-bee1-097dbb1765b2',1399,1400), ('8dbb5e67-3052-4f6e-a464-af3d7750ec13',299,300), ('6ea0b05c-33a0-4832-8658-4127c98ccc19',149,150), ('03f60aa4-42b4-4309-bd9d-f287d1d8cfc9',209,210), ('e8a515b2-dcd7-4771-927d-cf169fb87dd5',1380,1360), ('fa99e0c8-9309-4b2b-a34a-010574692a45',89,100), ('62d8c9d2-a8a8-4c52-a083-2b1a513b5fa0',1400,1315), ('5a4238d9-14bb-4772-86c8-840041bebb81',800,795), ('f9848f05-430b-4e5c-bdff-b8037f01f158',250,230), ('995b8db7-31d2-4db2-8cf1-f94e16560a9b',520,430), ('a8e09133-f283-4b58-82d9-cf93a57af5f8',200,2000), ('ad2324fc-3d66-448c-8830-73ef2ce0d727',300,298), ('f4e4a3c8-cd52-4277-9a6e-9d6f6e69c706',560,580);  DO $$ DECLARE   v_count integer; BEGIN   SELECT count(*) INTO v_count   FROM public.delivery_plans p   JOIN pg_temp.repair_expected e ON e.plan_id = p.id   WHERE p.deleted_at IS NULL     AND p.actual_qty = e.expected_old_actual;    IF v_count <> 14 THEN     RAISE EXCEPTION 'Du lieu da thay doi sau audit: chi %/14 dong con khop. Dung sua de tranh ghi de production.', v_count;   END IF;    IF EXISTS (     SELECT 1     FROM public.inventory_transactions b     JOIN pg_temp.repair_expected e ON e.plan_id = b.delivery_plan_id     LEFT JOIN public.shipment_logs s ON s.id = b.shipment_id     WHERE b.tx_type = 'out'       AND b.adjusted_from_transaction_id IS NULL       AND b.deleted_at IS NULL       AND (b.shipment_id IS NULL OR s.id IS NULL OR s.deleted_at IS NOT NULL)   ) THEN     RAISE EXCEPTION 'Co giao dich khong thuoc chuyen dang hieu luc. Dung sua de kiem tra lai.';   END IF;    CREATE TEMP TABLE repair_calculated ON COMMIT DROP AS   SELECT     e.plan_id,     COALESCE(sum(b.qty + COALESCE(a.adjustment_delta, 0)), 0) AS calculated_actual   FROM pg_temp.repair_expected e   LEFT JOIN public.inventory_transactions b     ON b.delivery_plan_id = e.plan_id    AND b.tx_type = 'out'    AND b.adjusted_from_transaction_id IS NULL    AND b.deleted_at IS NULL   LEFT JOIN LATERAL (     SELECT COALESCE(sum(CASE WHEN adj.tx_type = 'adjust_in' THEN adj.qty WHEN adj.tx_type = 'adjust_out' THEN -adj.qty ELSE 0 END), 0) AS adjustment_delta     FROM public.inventory_transactions adj     WHERE adj.adjusted_from_transaction_id = b.id       AND adj.deleted_at IS NULL   ) a ON true   GROUP BY e.plan_id;    IF EXISTS (     SELECT 1     FROM pg_temp.repair_expected e     JOIN pg_temp.repair_calculated c ON c.plan_id = e.plan_id     WHERE c.calculated_actual IS DISTINCT FROM e.expected_new_actual   ) THEN     RAISE EXCEPTION 'Giao dich kho da thay doi sau audit. Dung sua de tinh lai.';   END IF;    PERFORM 1   FROM public.delivery_plans p   JOIN pg_temp.repair_expected e ON e.plan_id = p.id   ORDER BY p.plan_date, p.id   FOR UPDATE OF p;    INSERT INTO public.delivery_plan_actual_repair_audit(plan_id, old_actual_qty, new_actual_qty, reason)   SELECT p.id, p.actual_qty, e.expected_new_actual, 'Doi chieu lai voi giao dich xuat kho cua chuyen dang hieu luc; giu nguyen lich su chot ngay va chuoi backlog'   FROM public.delivery_plans p   JOIN pg_temp.repair_expected e ON e.plan_id = p.id   ORDER BY p.plan_date, p.id;    PERFORM set_config('app.skip_delivery_backlog_sync', 'on', true);    UPDATE public.delivery_plans p   SET actual_qty = e.expected_new_actual,       updated_at = now()   FROM pg_temp.repair_expected e   WHERE p.id = e.plan_id     AND p.deleted_at IS NULL     AND p.actual_qty = e.expected_old_actual;    GET DIAGNOSTICS v_count = ROW_COUNT;   IF v_count <> 14 THEN     RAISE EXCEPTION 'Chi cap nhat duoc %/14 dong. Toan bo se quay lai.', v_count;   END IF;    PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true); EXCEPTION WHEN OTHERS THEN   PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true);   RAISE; END; $$;  COMMIT;  SELECT p.plan_date, pr.sku, a.old_actual_qty, a.new_actual_qty, a.repaired_at, a.reason FROM public.delivery_plan_actual_repair_audit a JOIN public.delivery_plans p ON p.id = a.plan_id JOIN public.products pr ON pr.id = p.product_id WHERE a.reason = 'Doi chieu lai voi giao dich xuat kho cua chuyen dang hieu luc; giu nguyen lich su chot ngay va chuoi backlog' ORDER BY a.repaired_at DESC, p.plan_date DESC, pr.sku;
